import java.io.*;
import java.util.*;

public class Main {
    private static int minAddToMakeValid(String s) {
        int balance = 0, insertions = 0;
        for (char c : s.toCharArray()) {
            if (c == '(') {
                balance++;
            } else { // c == ')'
                if (balance == 0) {
                    insertions++; // need a '(' before this ')'
                } else {
                    balance--; // match with a previous '('
                }
            }
        }
        return insertions + balance; // remaining '(' need ')'
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            String s = br.readLine().trim();
            out.append(minAddToMakeValid(s));
            if (t + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

